globalThis.fun=function(t){setTimeout(()=>{t=t||{};var o=$('<div class="joy"></div>').css({position:"fixed",width:100,top:(t.y||t.clientY||Math.random()*$(globalThis).height())-50,left:(t.x||t.clientX||t.pageX||Math.random()*$(globalThis).width())-50,transform:"rotate("+360*Math.random()+"deg)"}).appendTo("body");setTimeout(()=>{o.remove()},800)},10)},$(document).on("keyup",fun).on("touchstart",fun).on("mousedown",fun);